#include <bits/stdc++.h>
using namespace std;
const int N=1005;
int dp[N],w[N],c[N],g[N],n,m;
int main()
{
    cin>>m>>n;
    int group=-1;
    for(int i=1;i<=n;i++)
    {
        cin>>w[i]>>c[i]>>g[i];
        group=max(group,g[i]);
    }
    for(int i=1;i<=group;i++)
    {
        for(int j=m;j>=0;j--)
        {
            for(int k=1;k<=n;k++)
            {
                if(g[k]!=i||j<w[k]) continue;
                dp[j]=max(dp[j],dp[j-w[k]]+c[k]);
            }
        }
    }
    cout<<dp[m];
    return 0;
}
